20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_1x1_HWC_u8_u8_s8_sym_bias_fast_any(const u8_t * in_tensor,
28	                                                const uint16_t in_tensor_dim_x,
29	                                                const uint16_t in_tensor_dim_y,
30	                                                const uint16_t in_tensor_ch,
31	                                                const q7_t * ker_weight,
32	                                                const uint16_t out_tensor_ch,
33	                                                const uint16_t ker_dim_x,
34	                                                const uint16_t ker_dim_y,
35	                                                const uint16_t pad_x,
36	                                                const uint16_t pad_y,
37	                                                const uint16_t stride_x,
38	                                                const uint16_t stride_y,
39	                                                const q31_t * bias,
40	                                                const uint16_t pre_rshift,
41	                                                const uint16_t out_scale,
42	                                                const uint16_t post_rshift,
43	                                                u8_t * out_tensor,
44	                                                const uint16_t out_tensor_dim_x,
45	                                                const uint16_t out_tensor_dim_y,
46	                                                q15_t * in_tmp_buf)
47	{
48	#ifdef ENA_EMPTY_FUN
49	    //empty body
50	#else
51	    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0 || ker_dim_x != 1 || ker_dim_y != 1
52	            || pad_x != 0 || pad_y != 0 || stride_x != 1 || stride_y != 1)
53	    {
54	        /* check if the input dimension meets the constraints */
55	        return -1;
56	    }
57	
58	#ifdef ENA_VEC_ISA
59	#if defined(ENA_TILING) && (NDS_VEC_RVV_VERSION >= 1000) && defined(ENA_NDS_V5_VEC_DOT_PROD)
60	{
61	    // Runtime dispatch: query VLMAX for e8m4 to determine threshold
62	    long vl;
63	    long vlmax_e8m4;
64	    NDS_VEC_VSETVLI(vlmax_e8m4, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
65	    const long n_threshold = vlmax_e8m4 >> 2;
66	
67	    if (out_tensor_ch < n_threshold)
68	    {
69	        // Small N: VD4DOTSU GEMM path (vectorize K, no transpose)
70	        const long lhs_rows = in_tensor_dim_x * in_tensor_dim_y;
71	        const long rhs_rows = out_tensor_ch;
72	        const long rhs_cols = in_tensor_ch;
73	        const long lhs_cols_offset = in_tensor_ch;
74	
75	        long max_vl_per_vg_e8m1;
76	        NDS_VEC_VSETVLI(max_vl_per_vg_e8m1, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
77	
78	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
79	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum
80	
81	        const u8_t *lhs = (const u8_t *)in_tensor;
82	        const q7_t *rhs = ker_weight;
83	        u8_t *dst = out_tensor;
84	
85	        long rhs_rows_idx = 0;
86	        for (rhs_rows_idx = 0; (rhs_rows_idx + 4) <= rhs_rows; rhs_rows_idx += 4)
87	        {
88	            const u8_t *lhs_ptr = &lhs[0];
89	            u8_t       *dst_ptr = &dst[0];
90	
91	            //load bias for 4 output channels
92	            NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
93	            const q31_t *pBias = &bias[rhs_rows_idx];
94	            NDS_VEC_VLE32_V(NDS_VEC_V28, pBias);
95	
96	            long lhs_rows_idx = lhs_rows >> 2;
97	            while (lhs_rows_idx)
98	            {
99	                const q7_t *rhs_ptr  = &rhs[0];
100	                q7_t *rhs_ptr2 = (q7_t *)&rhs_ptr[rhs_cols];
101	                q7_t *rhs_ptr3 = (q7_t *)&rhs_ptr[rhs_cols * 2];
102	                q7_t *rhs_ptr4 = (q7_t *)&rhs_ptr[rhs_cols * 3];
103	                u8_t *lhs_ptr2 = (u8_t *)&lhs_ptr[lhs_cols_offset];
104	                u8_t *lhs_ptr3 = (u8_t *)&lhs_ptr[lhs_cols_offset * 2];
105	                u8_t *lhs_ptr4 = (u8_t *)&lhs_ptr[lhs_cols_offset * 3];
106	                long rhs_cols2 = rhs_cols;
107	
108	                NDS_VEC_VSETVLI(vl, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
109	                //clear v0~v15 (16 accumulators for 4x4 blocking)
110	                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
111	                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
112	
113	                while(rhs_cols2 >= max_vl_per_vg_e8m1)
114	                {
115	                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
116	                    NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
117	                    NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
118	                    NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
119	                    NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
120	                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
121	                    NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
122	                    NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
123	                    NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
124	                    rhs_cols2 -= vl;
125	                    rhs_ptr += vl;
126	                    rhs_ptr2 += vl;
127	                    rhs_ptr3 += vl;
128	                    rhs_ptr4 += vl;
129	                    lhs_ptr += vl;
130	                    lhs_ptr2 += vl;
131	                    lhs_ptr3 += vl;
132	                    lhs_ptr4 += vl;
133	
134	                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
135	                    // VD4DOTSU: unsigned lhs * signed rhs -> signed acc
136	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
137	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1, NDS_VEC_V17, NDS_VEC_V20);
138	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2, NDS_VEC_V20, NDS_VEC_V18);
139	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3, NDS_VEC_V20, NDS_VEC_V19);
140	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4, NDS_VEC_V21, NDS_VEC_V16);
141	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5, NDS_VEC_V21, NDS_VEC_V17);
142	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6, NDS_VEC_V21, NDS_VEC_V18);
143	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7, NDS_VEC_V21, NDS_VEC_V19);
144	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8, NDS_VEC_V22, NDS_VEC_V16);
145	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9, NDS_VEC_V22, NDS_VEC_V17);
146	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V22, NDS_VEC_V18);
147	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V22, NDS_VEC_V19);
148	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V23, NDS_VEC_V16);
149	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V23, NDS_VEC_V17);
150	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V23, NDS_VEC_V18);
151	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V23, NDS_VEC_V19);
152	                }
153	                while(rhs_cols2 > 0)
154	                {
155	                    //clean one of the sources for tail handling
156	                    long tmp_vl = rhs_cols2 + 3;
157	                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
158	                    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
159	                    NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
160	                    NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
161	                    NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);
162	
163	                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
164	                    NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
165	                    NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
166	                    NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
167	                    NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
168	                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
169	                    NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
170	                    NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
171	                    NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
172	                    rhs_cols2 -= vl;
173	                    rhs_ptr += vl;
174	                    rhs_ptr2 += vl;
175	                    rhs_ptr3 += vl;
176	                    rhs_ptr4 += vl;
177	                    lhs_ptr += vl;
178	                    lhs_ptr2 += vl;
179	                    lhs_ptr3 += vl;
180	                    lhs_ptr4 += vl;
181	
182	                    vl = (vl + 3) >> 2;
183	                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
184	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
185	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1, NDS_VEC_V17, NDS_VEC_V20);
186	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2, NDS_VEC_V20, NDS_VEC_V18);
187	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3, NDS_VEC_V20, NDS_VEC_V19);
188	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4, NDS_VEC_V21, NDS_VEC_V16);
189	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5, NDS_VEC_V21, NDS_VEC_V17);
190	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6, NDS_VEC_V21, NDS_VEC_V18);
191	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7, NDS_VEC_V21, NDS_VEC_V19);
192	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8, NDS_VEC_V22, NDS_VEC_V16);
193	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9, NDS_VEC_V22, NDS_VEC_V17);
194	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V22, NDS_VEC_V18);
195	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V22, NDS_VEC_V19);
196	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V23, NDS_VEC_V16);
197	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V23, NDS_VEC_V17);
198	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V23, NDS_VEC_V18);
199	                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V23, NDS_VEC_V19);
200	                }
201	
202	                // 16 VREDSUM reductions to scalar
203	                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
204	                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
205	                NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V1, NDS_VEC_V31);
206	                NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V2, NDS_VEC_V31);
207	                NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V3, NDS_VEC_V31);
208	                NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V4, NDS_VEC_V31);
209	                NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V5, NDS_VEC_V31);
210	                NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V6, NDS_VEC_V31);
211	                NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V7, NDS_VEC_V31);
212	                NDS_VEC_VREDSUM_VS(NDS_VEC_V4, NDS_VEC_V8, NDS_VEC_V31);
213	                NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V9, NDS_VEC_V31);
214	                NDS_VEC_VREDSUM_VS(NDS_VEC_V5, NDS_VEC_V10, NDS_VEC_V31);
215	                NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V11, NDS_VEC_V31);
216	                NDS_VEC_VREDSUM_VS(NDS_VEC_V6, NDS_VEC_V12, NDS_VEC_V31);
217	                NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V13, NDS_VEC_V31);
218	                NDS_VEC_VREDSUM_VS(NDS_VEC_V7, NDS_VEC_V14, NDS_VEC_V31);
219	                NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V15, NDS_VEC_V31);
220	
221	                // VSLIDEUP to pack 4 results into vectors of 4 elements
222	                // V0: [lhs0*rhs0, lhs0*rhs1, lhs0*rhs2, lhs0*rhs3]
223	                // V2: [lhs1*rhs0, lhs1*rhs1, lhs1*rhs2, lhs1*rhs3]
224	                // V4: [lhs2*rhs0, lhs2*rhs1, lhs2*rhs2, lhs2*rhs3]
225	                // V6: [lhs3*rhs0, lhs3*rhs1, lhs3*rhs2, lhs3*rhs3]
226	                NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
227	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V16, 1);
228	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1,  2);
229	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V17, 3);
230	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V18, 1);
231	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V3,  2);
232	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V19, 3);
233	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V20, 1);
234	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V5,  2);
235	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V21, 3);
236	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V22, 1);
237	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V7,  2);
238	                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V23, 3);
239	
240	                // Add bias
241	                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);
242	                NDS_VEC_VADD_VV(NDS_VEC_V2, NDS_VEC_V2, NDS_VEC_V28);
243	                NDS_VEC_VADD_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V28);
244	                NDS_VEC_VADD_VV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V28);
245	
246	                // Sym requantize: pre_rshift -> mul -> clamp -> narrow to u8
247	                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
248	                NDS_VEC_VSRA_VX(NDS_VEC_V2, NDS_VEC_V2, pre_rshift);
249	                NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, pre_rshift);
250	                NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, pre_rshift);
251	
252	                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
253	                NDS_VEC_VMUL_VX(NDS_VEC_V2, NDS_VEC_V2, out_scale);
254	                NDS_VEC_VMUL_VX(NDS_VEC_V4, NDS_VEC_V4, out_scale);
255	                NDS_VEC_VMUL_VX(NDS_VEC_V6, NDS_VEC_V6, out_scale);
256	
257	                NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
258	                NDS_VEC_VMAX_VX(NDS_VEC_V2, NDS_VEC_V2, 0);
259	                NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, 0);
260	                NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, 0);
261	
262	                // Narrow e32->e16 with post_rshift (unsigned clip)
263	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
264	                NDS_VEC_VNCLIPU_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
265	                NDS_VEC_VNCLIPU_WX(NDS_VEC_V2, NDS_VEC_V2, post_rshift);
266	                NDS_VEC_VNCLIPU_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
267	                NDS_VEC_VNCLIPU_WX(NDS_VEC_V6, NDS_VEC_V6, post_rshift);
268	
269	                // Narrow e16->e8 (unsigned clip)
270	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
271	                NDS_VEC_VNCLIPU_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
272	                NDS_VEC_VNCLIPU_WI(NDS_VEC_V2, NDS_VEC_V2, 0);
273	                NDS_VEC_VNCLIPU_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
274	                NDS_VEC_VNCLIPU_WI(NDS_VEC_V6, NDS_VEC_V6, 0);
275	
276	                // Store 4 output pixels, each with rhs_rows stride
277	                NDS_VEC_VSE8_V(NDS_VEC_V0, dst_ptr);
278	                dst_ptr += rhs_rows;
279	                NDS_VEC_VSE8_V(NDS_VEC_V2, dst_ptr);
280	                dst_ptr += rhs_rows;
281	                NDS_VEC_VSE8_V(NDS_VEC_V4, dst_ptr);
282	                dst_ptr += rhs_rows;
283	                NDS_VEC_VSE8_V(NDS_VEC_V6, dst_ptr);
284	                dst_ptr += rhs_rows;
285	                lhs_ptr -= rhs_cols;
286	                lhs_ptr += 4 * lhs_cols_offset;
287	                lhs_rows_idx--;
288	            }
289	
290	            // Left-over lhs rows (1-3 pixels)
291	            long rest_lhs_row = lhs_rows & 3;
292	            while(rest_lhs_row-- > 0)
293	            {
294	                const q7_t *rhs_ptr  = &rhs[0];
295	                q7_t *rhs_ptr2 = (q7_t *)&rhs_ptr[rhs_cols];
296	                q7_t *rhs_ptr3 = (q7_t *)&rhs_ptr[rhs_cols * 2];
297	                q7_t *rhs_ptr4 = (q7_t *)&rhs_ptr[rhs_cols * 3];
298	                long rhs_cols2 = rhs_cols;
299	
300	                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
301	                NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
302	                NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
303	                NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0x0);
304	                NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0x0);
